function Notifier(target){

    this.Target = target,
    this.priorities = [],
    this.subscribers = [],

    this.subscribe = function(fn) {
        this.subscribers.push(fn.bind(this.Target))
        return fn;
    }
    this.unsubscribe = function(fn) {
        this.subscribers = this.subscribers.filter(f => f != fn)
        return fn;
    }
    this.prioritize = function(fn) {
        this.priorities.push(fn)
        return fn
    }
    this.unprioritize = function(fn) {
        this.priorities = this.priorities.filter(f => f != fn);
    }
    this.notify = function() {
        if (this.hasPriorities) {
            this.priorities.forEach(fn => fn.call(this.Target))
        }
        if (!this.isEmpty)
            this.subscribers.forEach(fn => fn.call(this.Target));
    }

    Object.defineProperty(this,'isEmpty', {
        get() {
            return !(this.subscribers.length > 0);
        }
    })
    Object.defineProperty(this,'hasPriorities', {
        get() {
            return this.priorities.length > 0
        }
    })
}

class Modal {
    constructor(element) {

        this.element = element;
        this.openTimeLine = new Notifier(this);
        this.closeTimeLine = new Notifier(this);
        this.togglers = new Set();
        this.openers = new Set();
        this.closers = new Set();
        this.status = 'inactive';

    }

    set state(status) {

        // console.log(status,this.status)
        if (status == 'inactive') this.close();

        else if (status == 'active') this.open();

        else console.log('active and inactive are the only two states needed here',status)
    
    }

    get state() {
        return this.status;
    }

    open() {

        if (!this.openTimeLine.isEmpty) this.openTimeLine.notify();
        this.status = 'active'
    }
    close() {
        if (!this.closeTimeLine.isEmpty) this.closeTimeLine.notify();
        this.status = 'inactive'
    }
    toggle() {
        // console.log(this.state,this.status,this)

        if (this.state == 'inactive') this.state = 'active';

        else if (this.state == 'active') this.state = 'inactive';
        
        else console.log('err something went wrong with the modal toggler');
        
        return;

    }
    bindToggler(element) {
        // console.log(element)
        if (this.togglers.has(element)) return `${element} is already bound as a toggler`
        this.togglers.add(element)
        element.addEventListener('click',this.toggle.bind(this))
        return `${element} successfully bound as a toggler`
    }
    bindOpener(element) {

    }
    bindCloser(element) {
        // console.log(element)
        if (this.closers.has(element)) return `${element} is already bound as a closer`
        this.closers.add(element)
        element.addEventListener('click',this.close.bind(this))
        return `${element} successfully bound as a closer`
    }
    bindAccordian(reference) {
        this.accordian = reference;
        this.openTimeLine.prioritize(() => this.accordian.setActive(this))
    }
    
}

